import{_ as o,o as e,c as a,ae as i}from"./chunks/framework.BD9pLfSD.js";const m=JSON.parse('{"title":"Account Related Questions","description":"","frontmatter":{},"headers":[],"relativePath":"en/1-FAQ/1-account.md","filePath":"en/1-FAQ/1-account.md"}'),n={name:"en/1-FAQ/1-account.md"};function r(s,t,l,c,h,d){return e(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="account-related-questions" tabindex="-1">Account Related Questions <a class="header-anchor" href="#account-related-questions" aria-label="Permalink to &quot;Account Related Questions&quot;">​</a></h1><h2 id="registration-login" tabindex="-1">Registration &amp; Login <a class="header-anchor" href="#registration-login" aria-label="Permalink to &quot;Registration &amp; Login&quot;">​</a></h2><h3 id="q1-how-to-register-an-account" tabindex="-1">Q1: How to register an account? <a class="header-anchor" href="#q1-how-to-register-an-account" aria-label="Permalink to &quot;Q1: How to register an account?&quot;">​</a></h3><p><strong>A</strong>: Click the &quot;Login/Register&quot; button in the top right corner, select the &quot;Register&quot; tab, fill in email, password, name and other information, select role (subject/experimenter), submit and the system will send a verification email. Click the verification link in the email to complete registration.</p><h3 id="q2-forgot-password" tabindex="-1">Q2: Forgot password? <a class="header-anchor" href="#q2-forgot-password" aria-label="Permalink to &quot;Q2: Forgot password?&quot;">​</a></h3><p><strong>A</strong>: Click the &quot;Forgot Password&quot; link on the login page, enter your registered email, and the system will send a password reset email. Click the link in the email to set a new password.</p><h3 id="q3-how-to-switch-roles" tabindex="-1">Q3: How to switch roles? <a class="header-anchor" href="#q3-how-to-switch-roles" aria-label="Permalink to &quot;Q3: How to switch roles?&quot;">​</a></h3><p><strong>A</strong>: After logging in, go to personal center, select the role you want to switch to in &quot;Role Management&quot;, and click the &quot;Switch&quot; button.</p><h3 id="q4-email-verification-failed" tabindex="-1">Q4: Email verification failed? <a class="header-anchor" href="#q4-email-verification-failed" aria-label="Permalink to &quot;Q4: Email verification failed?&quot;">​</a></h3><p><strong>A</strong>: Please check if the verification link is expired, email address is correct, or click &quot;Resend Verification Email&quot;.</p><h3 id="q5-how-to-modify-personal-information" tabindex="-1">Q5: How to modify personal information? <a class="header-anchor" href="#q5-how-to-modify-personal-information" aria-label="Permalink to &quot;Q5: How to modify personal information?&quot;">​</a></h3><p><strong>A</strong>: After logging in, go to personal center, click &quot;Edit Profile&quot;, modify information, and click &quot;Save&quot;.</p><h3 id="q6-how-to-delete-account" tabindex="-1">Q6: How to delete account? <a class="header-anchor" href="#q6-how-to-delete-account" aria-label="Permalink to &quot;Q6: How to delete account?&quot;">​</a></h3><p><strong>A</strong>: Please contact platform administrator to request account deletion. Contact: <a href="/en/7-technical-support/1-contact.html">Technical Support</a></p>',14)])])}const f=o(n,[["render",r]]);export{m as __pageData,f as default};
